import numpy as np

def l1_norm(v):
    v = np.asarray(v, dtype=float)
    return float(np.sum(np.abs(v)))


def l1_distance(a, b):
    a = np.asarray(a, dtype=float)
    b = np.asarray(b, dtype=float)
    if a.shape != b.shape:
        raise ValueError(f"Shape mismatch: {a.shape} vs {b.shape}")
    return float(np.sum(np.abs(a - b)))

